script:
frappe.ui.form.on("Student Transport Assignment", {

    transport_route(frm) {

        if (!frm.doc.transport_route) return;

        frappe.db.get_doc("Transport Route", frm.doc.transport_route)
            .then(doc => {

                frm.set_value("pickup_point", doc.start_point);
                frm.set_value("drop_point", doc.end_point);
                frm.set_value("monthly_fee", doc.monthly_fee);

            });

    }

});
